class Person {
private:
    string name;
    int age;
public:
    Person(string n, int a) {
        name = n;
        age = a;
    }
    friend ostream& operator<<(ostream& os, const Person& p);
};

ostream& operator<<(ostream& os, const Person& p) {
    os << p.name << " (" << p.age << " years old)";
    return os;
}

int main() {
    Person p("Bob", 25);
    cout << p << endl;
    return 0;
}
